import{_ as s,o as a,c as n,ai as t}from"./chunks/framework.CaiDwmc7.js";const h=JSON.parse('{"title":"Files Screen","description":"Two-pane file tree browser with syntax highlighting, git status badges, multi-tab support, fuzzy search, inline editing, and git blame.","frontmatter":{"title":"Files Screen","description":"Two-pane file tree browser with syntax highlighting, git status badges, multi-tab support, fuzzy search, inline editing, and git blame.","outline":[2,3]},"headers":[],"relativePath":"cli/screens/files.md","filePath":"cli/screens/files.md","lastUpdated":1772487797000}'),i={name:"cli/screens/files.md"};function l(p,e,r,d,o,c){return a(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="files-screen" tabindex="-1">Files Screen <a class="header-anchor" href="#files-screen" aria-label="Permalink to “Files Screen”">​</a></h1><p>A two-pane file tree browser with preview. Left pane shows an expandable directory tree with git status badges; right pane shows file content with line numbers, syntax highlighting, multi-tab support, inline editing, and git blame annotations.</p><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to “Features”">​</a></h2><ul><li><strong>Syntax highlighting</strong> (F-1): Chroma-based highlighting for 100+ languages</li><li><strong>Git status badges</strong> (F-2): Modified (M/yellow), Added (A/green), Deleted (D/red), Untracked (?/gray) indicators on tree items</li><li><strong>Multi-tab support</strong> (F-3): Open multiple files in tabs, switch with <code>h</code>/<code>l</code>, close with <code>x</code>, max 10 tabs</li><li><strong>Fuzzy file finder</strong> (F-4): <code>Ctrl+D</code> opens a project-wide fuzzy file search overlay. File cache built asynchronously via <code>git ls-files</code> (or <code>filepath.Walk</code> fallback). Scoring: +10 per character match, +5 consecutive bonus, +8 separator boundary, +6 camelCase boundary, +15 filename start, -2 per gap. Shorter paths preferred as tiebreaker</li><li><strong>Content search</strong> (F-5): <code>Ctrl+S</code> opens a ripgrep-powered project-wide content search (<code>rg --json --max-count 30</code>). Results show file:line:text with navigation. Displays install instructions if <code>rg</code> binary not found</li><li><strong>Inline file editing</strong> (F-6): <code>e</code> opens a full textarea editor, <code>Ctrl+S</code> saves, <code>Esc</code> cancels</li><li><strong>Git blame view</strong> (F-7): <code>b</code> toggles blame annotations (short hash, author, relative age) alongside code</li></ul><h2 id="ui-layout" tabindex="-1">UI Layout <a class="header-anchor" href="#ui-layout" aria-label="Permalink to “UI Layout”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>╭───────────── 30% ───────────────╮╭──────────────── 70% ──────────────────────╮</span></span>
<span class="line"><span>│ FILES                            ││ [main.go] [view.go] [model.go]            │</span></span>
<span class="line"><span>│ ──────────────────────────────  ││ main.go [go]                              │</span></span>
<span class="line"><span>│ ▼ prism-plugin/                 ││ ──────────────────────────────────────    │</span></span>
<span class="line"><span>│   ▼ cmd/                        ││   1 │ package main                        │</span></span>
<span class="line"><span>│     ▼ prism-cli/                ││   2 │                                      │</span></span>
<span class="line"><span>│       ▶ app/                    ││   3 │ import (                             │</span></span>
<span class="line"><span>│       ▶ claude/                 ││   4 │   &quot;fmt&quot;                              │</span></span>
<span class="line"><span>│     &gt; README.md             M   ││   5 │   &quot;os&quot;                               │</span></span>
<span class="line"><span>│   ▶ .prism/                     ││   6 │ )                                    │</span></span>
<span class="line"><span>│   &gt; go.mod                  M   ││                                            │</span></span>
<span class="line"><span>│                                  ││                                            │</span></span>
<span class="line"><span>│                        ▐ (scroll)││                                            │</span></span>
<span class="line"><span>╰──────────────────────────────────╯╰──────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Blame mode (\`b\` in preview pane):</span></span>
<span class="line"><span>╭──────────────── 70% ──────────────────────────────────────╮</span></span>
<span class="line"><span>│ abcdef12 JohnDoe   3d │    1 │ package main               │</span></span>
<span class="line"><span>│ abcdef12 JohnDoe   3d │    2 │                             │</span></span>
<span class="line"><span>│ 1234abcd Alice     2mo │    3 │ import (                    │</span></span>
<span class="line"><span>│ 1234abcd Alice     2mo │    4 │   &quot;fmt&quot;                     │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br></div></div><h2 id="ui-layout-—-filter-mode" tabindex="-1">UI Layout — Filter Mode <a class="header-anchor" href="#ui-layout-—-filter-mode" aria-label="Permalink to “UI Layout — Filter Mode”">​</a></h2><p>Activated with <code>/</code> in the tree pane. The tree header is replaced with a search input and the tree is filtered to matching files:</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>╭───────────── 30% ───────────────╮╭──────────────── 70% ──────────────────────╮</span></span>
<span class="line"><span>│ [Filter: mod                   ]││ [main.go] [view.go] [model.go]            │</span></span>
<span class="line"><span>│ ──────────────────────────────  ││ model.go [go]                             │</span></span>
<span class="line"><span>│   &gt; model.go                M   ││ ──────────────────────────────────────    │</span></span>
<span class="line"><span>│   &gt; go.mod                  M   ││   1 │ package main                        │</span></span>
<span class="line"><span>│                                  ││   2 │                                      │</span></span>
<span class="line"><span>│                                  ││   3 │ type Model struct {                 │</span></span>
<span class="line"><span>│                                  ││   4 │   Width  int                        │</span></span>
<span class="line"><span>│                                  ││   5 │   Height int                        │</span></span>
<span class="line"><span>│                                  ││   6 │ }                                   │</span></span>
<span class="line"><span>│                                  ││                                            │</span></span>
<span class="line"><span>╰──────────────────────────────────╯╰──────────────────────────────────────────╯</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>Footer hints change to: <code>esc cancel search • enter apply filter</code></p><h2 id="ui-layout-—-edit-mode" tabindex="-1">UI Layout — Edit Mode <a class="header-anchor" href="#ui-layout-—-edit-mode" aria-label="Permalink to “UI Layout — Edit Mode”">​</a></h2><p>Activated with <code>e</code> in the preview pane. The preview content is replaced with an editable textarea:</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>╭───────────── 30% ───────────────╮╭──────────────── 70% ──────────────────────╮</span></span>
<span class="line"><span>│ FILES                            ││ [main.go] [view.go] [model.go]            │</span></span>
<span class="line"><span>│ ──────────────────────────────  ││ model.go [go] — EDITING                   │</span></span>
<span class="line"><span>│ ▼ prism-plugin/                 ││ ──────────────────────────────────────    │</span></span>
<span class="line"><span>│   ▼ cmd/                        ││ package main                              │</span></span>
<span class="line"><span>│     ▼ prism-cli/                ││                                            │</span></span>
<span class="line"><span>│       ▶ app/                    ││ type Model struct {                        │</span></span>
<span class="line"><span>│       ▶ claude/                 ││   Width  int                               │</span></span>
<span class="line"><span>│     &gt; README.md             M   ││   Height int█                              │</span></span>
<span class="line"><span>│   ▶ .prism/                     ││   Ready  bool                              │</span></span>
<span class="line"><span>│   &gt; go.mod                  M   ││ }                                          │</span></span>
<span class="line"><span>│                                  ││                                            │</span></span>
<span class="line"><span>╰──────────────────────────────────╯╰──────────────────────────────────────────╯</span></span>
<span class="line"><span>  ctrl+s save • esc cancel edit</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p>The tree pane is dimmed (inactive border). Cursor (<code>█</code>) visible in textarea. Tab bar remains at top of preview pane.</p><h2 id="key-bindings" tabindex="-1">Key Bindings <a class="header-anchor" href="#key-bindings" aria-label="Permalink to “Key Bindings”">​</a></h2><p><strong>Tree Pane (left):</strong></p><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>j</code> / <code>↓</code></td><td>Move cursor down, load preview</td></tr><tr><td><code>k</code> / <code>↑</code></td><td>Move cursor up, load preview</td></tr><tr><td><code>Enter</code> / <code>Space</code></td><td>Toggle directory expand/collapse, or open in tab</td></tr><tr><td><code>x</code></td><td>Close active tab</td></tr><tr><td><code>/</code></td><td>Enter filter mode (filename search)</td></tr><tr><td><code>Tab</code></td><td>Switch to preview pane</td></tr><tr><td><code>Esc</code> / <code>Backspace</code></td><td>Focus Home</td></tr></tbody></table><p><strong>Preview Pane (right):</strong></p><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>j</code> / <code>↓</code></td><td>Scroll preview down</td></tr><tr><td><code>k</code> / <code>↑</code></td><td>Scroll preview up</td></tr><tr><td><code>h</code> / <code>←</code></td><td>Previous tab</td></tr><tr><td><code>l</code> / <code>→</code></td><td>Next tab</td></tr><tr><td><code>b</code></td><td>Toggle git blame annotations</td></tr><tr><td><code>e</code></td><td>Enter edit mode</td></tr><tr><td><code>x</code></td><td>Close active tab</td></tr><tr><td><code>Esc</code></td><td>Switch back to tree pane</td></tr></tbody></table><p><strong>Edit Mode</strong> (<code>e</code> from preview pane):</p><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>Ctrl+S</code></td><td>Save file to disk</td></tr><tr><td><code>Esc</code></td><td>Cancel editing, discard changes</td></tr></tbody></table><p><strong>Filter Mode:</strong> Captures all keystrokes for search query. <code>Esc</code> cancels, <code>Enter</code> applies, <code>Backspace</code> deletes.</p><p><strong>Global overlays (from Files Screen):</strong></p><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>Ctrl+D</code></td><td>Open fuzzy file finder overlay (F-4)</td></tr><tr><td><code>Ctrl+S</code></td><td>Open content search overlay (F-5)</td></tr></tbody></table>`,24)])])}const u=s(i,[["render",l]]);export{h as __pageData,u as default};
